// Script Continued Below
// RAJ 2020.02.18  STRY0063547 - Works with 2 UI Actions that Enable and Disable Shared Attachments for Stories STRY0060676 and STRY0063747
// if form action is either Enable Shared Attachments or Disable Shared Attachments, then prompt user before proceding.
function onSubmit() {
    var formAction = g_form.getActionName();
    if (formAction == 'delete_template') {
        confirmDeleteTemplate();
		// returning true opens UI Page but does not allow user interaction, then auto closes the UI Page
        return false;
    }	
}
function confirmDeleteTemplate() {
    var templateNumberShortDescription = g_scratchpad.templateNumber + ': ' +g_scratchpad.templateName;
    var messageTitle = getMessage('Delete') + ' ' + templateNumberShortDescription + '?';

    // Use widget for Portal
    if (typeof spModal != 'undefined') {
        spModal.open({
            title: messageTitle,
            backdrop: 'static',
            widget: 'tasker_modal_delete_prompt',
            widgetInput: {
                'templateSysId': g_form.getUniqueValue(),
                'templateNumberShortDescription': templateNumberShortDescription
            },
            buttons: [],
			// Hide the <div> with class modal-footer that gets auto inserted from spModal, adds an element style
			footerStyle: { 'display': 'none' }
        }).then(function() {
            //jslog('numberofsubtasks');
        });
        return false;
    } else if (typeof spModal == 'undefined') {
        // For Platform use UI Page named: delete_task_prompt
		// STRY0119138 - changed name as it is used for task, template and template task
        var gm = new GlideModal('x_153465_discovert_tasker_delete_prompt');
        gm.setTitle(messageTitle);
		gm.setPreference('sysparm_templateNumberShortDescription', templateNumberShortDescription);
        gm.setPreference('sysparm_templateSysId', g_form.getUniqueValue());
        gm.setWidth(550);
        gm.render();
    }
}
